    // Extract rows safely from the correct page
    const bulbsGrid = context?.Form?.Page8?.LEDBulbsGrid || [];
    const bulbTypeCode = "SCE17LILG003-A"; // Code for PAR Lamps

    // Filter bulbs by type and sum their values
    const total = bulbsGrid.reduce((sum, currentRow) => {
        // Check if this bulb has the target type code
        if (currentRow?.BulbType?.Value === bulbTypeCode) {
            // Add its quantity to the sum
            return sum + (parseFloat(currentRow?.BulbQuantity?.Value) || 0);
        }
        // If not the target type, just return the current sum
        return sum;
    }, 0); // Start with initial value of 0

    // Return the total as a number
    return total;
